// Basic drag-and-drop with resizing example
class DraggableComponent {
  constructor(element) {
    this.element = element;
    this.isDragging = false;
    this.isResizing = false;
    this.offsetX = 0;
    this.offsetY = 0;

    element.addEventListener('mousedown', this.startDrag.bind(this));
    element.addEventListener('mousemove', this.drag.bind(this));
    element.addEventListener('mouseup', this.stopDrag.bind(this));
    element.addEventListener('mouseleave', this.stopDrag.bind(this));
  }

  startDrag(e) {
    if (e.target.classList.contains('resize-handle')) {
      this.isResizing = true;
    } else {
      this.isDragging = true;
      this.offsetX = e.clientX - this.element.getBoundingClientRect().left;
      this.offsetY = e.clientY - this.element.getBoundingClientRect().top;
      this.element.style.cursor = 'grabbing';
    }
  }

  drag(e) {
    if (this.isDragging) {
      this.element.style.left = `${e.clientX - this.offsetX}px`;
      this.element.style.top = `${e.clientY - this.offsetY}px`;
    } else if (this.isResizing) {
      this.element.style.width = `${e.clientX - this.element.getBoundingClientRect().left}px`;
      this.element.style.height = `${e.clientY - this.element.getBoundingClientRect().top}px`;
    }
  }

  stopDrag() {
    this.isDragging = false;
    this.isResizing = false;
    this.element.style.cursor = '';
  }
}

// Usage: new DraggableComponent(document.getElementById('my-component'));
